#ifndef GQA_PAGED_DECODE_KERNEL_H
#define GQA_PAGED_DECODE_KERNEL_H

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>
#include <ATen/ATen.h>
#include <tuple>

// Constants matching specification
constexpr int NUM_QO_HEADS = 32;
constexpr int NUM_KV_HEADS = 8;
constexpr int HEAD_DIM = 128;
constexpr int PAGE_SIZE = 1;
constexpr int GQA_RATIO = NUM_QO_HEADS / NUM_KV_HEADS; // 4

// Strides
constexpr int KV_HEAD_STRIDE = HEAD_DIM; // 128
constexpr int PAGE_STRIDE = NUM_KV_HEADS * HEAD_DIM; // 1024

/**
 * CUDA Kernel for GQA Paged Decode
 * 
 * Configuration:
 * - Grid: batch_size blocks
 * - Block: NUM_QO_HEADS threads (32)
 * - Each thread handles one query head
 * - Threads 0-3 share KV Head 0, 4-7 share KV Head 1, etc.
 */
__global__ void gqa_paged_decode_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int* __restrict__ kv_indptr,
    const int* __restrict__ kv_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int batch_size,
    float sm_scale
);

/**
 * Host function to launch the kernel
 */
void launch_gqa_paged_decode(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale,
    torch::Tensor output,
    torch::Tensor lse
);

#endif // GQA_PAGED_DECODE_KERNEL_H

#include "kernel.h"
#include <math_constants.h>
#include <cuda_fp16.h>
#include <cuda_runtime.h>

// Helper to load BF16 to FP32
__device__ inline float load_bf16_to_fp32(const __nv_bfloat16* ptr, int idx) {
    return __bfloat162float(ptr[idx]);
}

// Helper to store FP32 to BF16
__device__ inline void store_fp32_to_bf16(__nv_bfloat16* ptr, int idx, float val) {
    ptr[idx] = __float2bfloat16(val);
}

__global__ void gqa_paged_decode_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int* __restrict__ kv_indptr,
    const int* __restrict__ kv_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int batch_size,
    float sm_scale
) {
    int batch_idx = blockIdx.x;
    int head_idx = threadIdx.x;

    if (batch_idx >= batch_size || head_idx >= NUM_QO_HEADS) return;

    // Determine KV head for this query head (GQA: 4 query heads per KV head)
    int kv_head = head_idx / GQA_RATIO;
    int thread_in_group = head_idx % GQA_RATIO;

    // Load Q for this batch and head
    // q shape: [batch_size, num_qo_heads, head_dim]
    // Stride: num_qo_heads * head_dim
    int q_base_offset = batch_idx * NUM_QO_HEADS * HEAD_DIM + head_idx * HEAD_DIM;

    // Load Q into FP32 registers
    float q_vec[HEAD_DIM];
    for (int i = 0; i < HEAD_DIM; ++i) {
        q_vec[i] = load_bf16_to_fp32(q, q_base_offset + i);
    }

    // Get sequence range for this batch item
    int seq_start = kv_indptr[batch_idx];
    int seq_end = kv_indptr[batch_idx + 1];
    int seq_len = seq_end - seq_start;

    // Initialize Softmax State
    float max_val = -INFINITY;
    float sum_exp = 0.0f;
    float output_acc[HEAD_DIM] = {0.0f};

    if (seq_len > 0) {
        // Iterate over sequence tokens (pages)
        for (int s = seq_start; s < seq_end; ++s) {
            int page_id = kv_indices[s];

            // Calculate pointers for K and V for this page and kv_head
            // k_cache shape: [num_pages, 1, num_kv_heads, head_dim]
            // Flattened stride: PAGE_STRIDE per page, KV_HEAD_STRIDE per head
            int k_base_offset = page_id * PAGE_STRIDE + kv_head * KV_HEAD_STRIDE;
            int v_base_offset = page_id * PAGE_STRIDE + kv_head * KV_HEAD_STRIDE;

            // Load K and V for the current token
            // Use warp shuffle to share load among threads sharing the same KV head
            // Threads 0, 4, 8... (where thread_in_group == 0) load, others broadcast
            float k_vec[HEAD_DIM];
            float v_vec[HEAD_DIM];

            if (thread_in_group == 0) {
                for (int i = 0; i < HEAD_DIM; ++i) {
                    k_vec[i] = load_bf16_to_fp32(k_cache, k_base_offset + i);
                    v_vec[i] = load_bf16_to_fp32(v_cache, v_base_offset + i);
                }
            }

            // Broadcast K and V to other threads in the group using shfl
            // Mask covers the warp (32 threads). All threads in block are in one warp.
            unsigned mask = 0xFFFFFFFF;
            for (int i = 0; i < HEAD_DIM; ++i) {
                k_vec[i] = __shfl_sync(mask, k_vec[i], (head_idx & ~3)); // Broadcast from leader of group
                v_vec[i] = __shfl_sync(mask, v_vec[i], (head_idx & ~3));
            }

            // Compute Dot Product Q * K
            float dot_product = 0.0f;
            for (int i = 0; i < HEAD_DIM; ++i) {
                dot_product += q_vec[i] * k_vec[i];
            }
            float logit = dot_product * sm_scale;

            // Online Softmax Update
            float new_max = fmaxf(max_val, logit);
            float scale = expf(max_val - new_max);
            sum_exp = sum_exp * scale + expf(logit - new_max);

            // Accumulate Output
            float logit_scale = expf(logit - new_max);
            for (int i = 0; i < HEAD_DIM; ++i) {
                output_acc[i] = output_acc[i] * scale + logit_scale * v_vec[i];
            }

            max_val = new_max;
        }

        // Finalize Output and LSE
        // LSE = max_val + log(sum_exp)
        // Output = output_acc / sum_exp
        // Reference LSE is divided by log(2)

        float lse_val = -INFINITY;
        if (sum_exp > 0.0f) {
            lse_val = max_val + logf(sum_exp);
            float inv_sum = 1.0f / sum_exp;
            for (int i = 0; i < HEAD_DIM; ++i) {
                output_acc[i] *= inv_sum;
            }
        }

        // Convert LSE to base-2 log (divide by log(2))
        lse_val = lse_val / 0.6931471805599453f;

        // Store Output (BF16)
        int out_offset = batch_idx * NUM_QO_HEADS * HEAD_DIM + head_idx * HEAD_DIM;
        for (int i = 0; i < HEAD_DIM; ++i) {
            store_fp32_to_bf16(output, out_offset + i, output_acc[i]);
        }

        // Store LSE (FP32)
        int lse_offset = batch_idx * NUM_QO_HEADS + head_idx;
        lse[lse_offset] = lse_val;

    } else {
        // No tokens in sequence
        // Output 0
        int out_offset = batch_idx * NUM_QO_HEADS * HEAD_DIM + head_idx * HEAD_DIM;
        for (int i = 0; i < HEAD_DIM; ++i) {
            store_fp32_to_bf16(output, out_offset + i, 0.0f);
        }
        // LSE -inf
        int lse_offset = batch_idx * NUM_QO_HEADS + head_idx;
        lse[lse_offset] = -INFINITY;
    }
}

void launch_gqa_paged_decode(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale,
    torch::Tensor output,
    torch::Tensor lse
) {
    // Validation
    TORCH_CHECK(q.device().is_cuda(), "q must be on CUDA");
    TORCH_CHECK(k_cache.device().is_cuda(), "k_cache must be on CUDA");
    TORCH_CHECK(v_cache.device().is_cuda(), "v_cache must be on CUDA");
    TORCH_CHECK(kv_indptr.device().is_cuda(), "kv_indptr must be on CUDA");
    TORCH_CHECK(kv_indices.device().is_cuda(), "kv_indices must be on CUDA");
    TORCH_CHECK(output.device().is_cuda(), "output must be on CUDA");
    TORCH_CHECK(lse.device().is_cuda(), "lse must be on CUDA");

    TORCH_CHECK(q.dtype() == torch::kBFloat16, "q must be bfloat16");
    TORCH_CHECK(k_cache.dtype() == torch::kBFloat16, "k_cache must be bfloat16");
    TORCH_CHECK(v_cache.dtype() == torch::kBFloat16, "v_cache must be bfloat16");
    TORCH_CHECK(kv_indptr.dtype() == torch::kInt32, "kv_indptr must be int32");
    TORCH_CHECK(kv_indices.dtype() == torch::kInt32, "kv_indices must be int32");
    TORCH_CHECK(output.dtype() == torch::kBFloat16, "output must be bfloat16");
    TORCH_CHECK(lse.dtype() == torch::kFloat32, "lse must be float32");

    int batch_size = q.size(0);
    TORCH_CHECK(q.size(1) == NUM_QO_HEADS, "num_qo_heads must be 32");
    TORCH_CHECK(q.size(2) == HEAD_DIM, "head_dim must be 128");

    TORCH_CHECK(kv_indptr.size(0) == batch_size + 1, "kv_indptr length must be batch_size + 1");
    TORCH_CHECK(output.size(0) == batch_size, "output batch size mismatch");
    TORCH_CHECK(output.size(1) == NUM_QO_HEADS, "output num_qo_heads mismatch");
    TORCH_CHECK(output.size(2) == HEAD_DIM, "output head_dim mismatch");
    TORCH_CHECK(lse.size(0) == batch_size, "lse batch size mismatch");
    TORCH_CHECK(lse.size(1) == NUM_QO_HEADS, "lse num_qo_heads mismatch");

    // Launch Kernel
    int threads_per_block = NUM_QO_HEADS;
    int blocks_per_grid = batch_size;

    // Use explicit cast to ensure proper type resolution
    const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<c10::BFloat16>());
    const __nv_bfloat16* k_cache_ptr = reinterpret_cast<const __nv_bfloat16*>(k_cache.data_ptr<c10::BFloat16>());
    const __nv_bfloat16* v_cache_ptr = reinterpret_cast<const __nv_bfloat16*>(v_cache.data_ptr<c10::BFloat16>());
    __nv_bfloat16* output_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<c10::BFloat16>());

    gqa_paged_decode_kernel<<<blocks_per_grid, threads_per_block>>>(
        q_ptr,
        k_cache_ptr,
        v_cache_ptr,
        kv_indptr.data_ptr<int>(),
        kv_indices.data_ptr<int>(),
        output_ptr,
        lse.data_ptr<float>(),
        batch_size,
        sm_scale
    );

    // Error Checking
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }

    // Synchronize to ensure completion before returning
    cudaDeviceSynchronize();
}

#include <torch/extension.h>
#include "kernel.h"
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>

/**
 * Main run function that executes the GQA Paged Decode kernel
 * This is the entry point that matches the reference implementation signature
 * Accepts output tensors as arguments for in-place modification
 */
void run(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale,
    torch::Tensor output,
    torch::Tensor lse
) {
    launch_gqa_paged_decode(q, k_cache, v_cache, kv_indptr, kv_indices, sm_scale, output, lse);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GQA Paged Decode Kernel (A800 Optimized)");
}
